@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  padding: 0.75rem;
  font-size: 13px;
}

.timeline {
  display: flex;
  flex-direction: column;
  gap: 0;
}

.entry {
  display: flex;
  gap: 12px;
  position: relative;
  padding-bottom: 16px;
}

.entry:last-child {
  padding-bottom: 0;
}

.entry:last-child .line {
  display: none;
}

.dot-col {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex-shrink: 0;
  width: 28px;
}

.dot {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  flex-shrink: 0;
  z-index: 1;
}

.dot-status {
  background: rgba(163, 232, 81, 0.15);
  border: 1.5px solid #A3E851;
  color: #A3E851;
}

.dot-field {
  background: rgba(70, 155, 192, 0.15);
  border: 1.5px solid #469BC0;
  color: #469BC0;
}

.dot-parts {
  background: rgba(5, 4, 46, 0.08);
  border: 1.5px solid #05042E;
  color: #05042E;
}

.line {
  width: 2px;
  background: rgba(0, 0, 0, 0.06);
  flex: 1;
  margin-top: 4px;
}

.content {
  flex: 1;
  padding-top: 4px;
}

.event-header {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}

.badge {
  font-size: 10px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.badge-status {
  background: rgba(163, 232, 81, 0.15);
  color: #5a8a1a;
  border: 1px solid rgba(163, 232, 81, 0.4);
}

.badge-field {
  background: rgba(70, 155, 192, 0.15);
  color: #469BC0;
  border: 1px solid rgba(70, 155, 192, 0.3);
}

.badge-parts {
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
  border: 1px solid rgba(5, 4, 46, 0.15);
}

.event-time {
  font-size: 11px;
  color: #888780;
  font-weight: 500;
}

.event-user {
  font-size: 11px;
  color: #888780;
}

.event-detail {
  margin-top: 4px;
  font-size: 12px;
  color: #05042E;
  font-weight: 500;
}

.change-row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 3px;
  font-size: 12px;
}

.old-val {
  color: #888780;
  text-decoration: line-through;
}

.arrow {
  color: #888780;
  font-size: 10px;
}

.new-val {
  color: #05042E;
  font-weight: 600;
}

.notes {
  margin-top: 4px;
  font-size: 11px;
  color: #469BC0;
  font-style: italic;
}

.field-label {
  font-size: 11px;
  color: #888780;
  text-transform: capitalize;
}

.empty {
  font-size: 13px;
  color: #888780;
  text-align: center;
  padding: 2rem;
}

