function formatTime(ts) {
  if (!ts) return '';
  var d = new Date(ts);
  return d.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  }) + ' ' + d.toLocaleTimeString('en-GB', {
    hour: '2-digit',
    minute: '2-digit'
  });
}
function formatMovementType(mt) {
  if (!mt) return '';
  return mt.replace(/_/g, ' ').replace(/\b\w/g, function (c) {
    return c.toUpperCase();
  });
}
function getDotClass(eventType) {
  if (eventType === 'Status Change') return 'dot dot-status';
  if (eventType === 'Parts') return 'dot dot-parts';
  return 'dot dot-field';
}
function getBadgeClass(eventType) {
  if (eventType === 'Status Change') return 'badge badge-status';
  if (eventType === 'Parts') return 'badge badge-parts';
  return 'badge badge-field';
}
function getDotIcon(eventType) {
  if (eventType === 'Status Change') return '●';
  if (eventType === 'Parts') return '⚙';
  return '✎';
}
function render(m) {
  var timeline = document.getElementById('timeline');
  var empty = document.getElementById('empty-state');
  var history = m.history || [];
  if (!history.length) {
    empty.style.display = 'block';
    return;
  }
  empty.style.display = 'none';
  timeline.innerHTML = '';
  history.forEach(function (row) {
    var entry = document.createElement('div');
    entry.className = 'entry';
    var dotCol = document.createElement('div');
    dotCol.className = 'dot-col';
    var dot = document.createElement('div');
    dot.className = getDotClass(row.event_type);
    dot.textContent = getDotIcon(row.event_type);
    var line = document.createElement('div');
    line.className = 'line';
    dotCol.appendChild(dot);
    dotCol.appendChild(line);
    var content = document.createElement('div');
    content.className = 'content';

    // Header row
    var header = document.createElement('div');
    header.className = 'event-header';
    var badge = document.createElement('span');
    badge.className = getBadgeClass(row.event_type);
    badge.textContent = row.event_type;
    var time = document.createElement('span');
    time.className = 'event-time';
    time.textContent = formatTime(row.event_time);
    var user = document.createElement('span');
    user.className = 'event-user';
    user.textContent = row.changed_by ? '· ' + row.changed_by : '';
    header.appendChild(badge);
    header.appendChild(time);
    header.appendChild(user);
    content.appendChild(header);

    // Detail
    if (row.event_type === 'Status Change') {
      var detail = document.createElement('div');
      detail.className = 'event-detail';
      detail.textContent = '→ ' + (row.new_value || '');
      content.appendChild(detail);
    } else if (row.event_type === 'Field Edit') {
      var fieldLbl = document.createElement('div');
      fieldLbl.className = 'field-label';
      fieldLbl.textContent = (row.field_name || '').replace(/_/g, ' ');
      content.appendChild(fieldLbl);
      if (row.old_value || row.new_value) {
        var changeRow = document.createElement('div');
        changeRow.className = 'change-row';
        if (row.old_value) {
          var oldVal = document.createElement('span');
          oldVal.className = 'old-val';
          oldVal.textContent = row.old_value;
          changeRow.appendChild(oldVal);
          var arrow = document.createElement('span');
          arrow.className = 'arrow';
          arrow.textContent = '→';
          changeRow.appendChild(arrow);
        }
        var newVal = document.createElement('span');
        newVal.className = 'new-val';
        newVal.textContent = row.new_value || '';
        changeRow.appendChild(newVal);
        content.appendChild(changeRow);
      }
    } else if (row.event_type === 'Parts') {
      var detail = document.createElement('div');
      detail.className = 'event-detail';
      detail.textContent = formatMovementType(row.field_name);
      content.appendChild(detail);
      if (row.notes) {
        var notes = document.createElement('div');
        notes.className = 'notes';
        notes.textContent = row.notes;
        content.appendChild(notes);
      }
    }
    entry.appendChild(dotCol);
    entry.appendChild(content);
    timeline.appendChild(entry);
  });
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (m) {
  render(m);
});

